const config = $('Konfiguration').first().json;
const rows = $json.data || [];

let income = 0;
let expenses = 0;
let countIncome = 0;
let countExpenses = 0;

for (const row of rows) {
  const txs = row.attributes?.transactions || [];

  for (const tx of txs) {
    const type = String(tx.type || '').toLowerCase();
    const amount = Math.abs(Number(String(tx.amount || '0').replace(',', '.')));

    if (!amount || Number.isNaN(amount)) continue;

    if (type === 'deposit') {
      income += amount;
      countIncome++;
    }

    if (type === 'withdrawal') {
      expenses += amount;
      countExpenses++;
    }
  }
}

const balance = income - expenses;

const line = `firefly_month,month=${config.month} income=${income.toFixed(2)},expenses=${expenses.toFixed(2)},balance=${balance.toFixed(2)},count_income=${countIncome},count_expenses=${countExpenses}`;

return [
  {
    json: {
      ...config,
      income,
      expenses,
      balance,
      count_income: countIncome,
      count_expenses: countExpenses,
      influx_line: line
    }
  }
];
